export declare const SCHEMA_VERSION = 5;
export declare const ROOT_INODE = 1;
export declare const CORE_STATEMENTS: readonly ["CREATE TABLE IF NOT EXISTS vfs_meta (\n    k TEXT PRIMARY KEY,\n    v INTEGER NOT NULL\n  )", "CREATE TABLE IF NOT EXISTS vfs_nodes (\n    inode         INTEGER PRIMARY KEY AUTOINCREMENT,\n    type          TEXT    NOT NULL CHECK(type IN ('file','dir','symlink')),\n    mode          INTEGER NOT NULL DEFAULT 493,\n    mtime         INTEGER NOT NULL,\n    rev           INTEGER NOT NULL DEFAULT 0,\n    mount_root    TEXT,\n    stub_size     INTEGER,\n    manifest_hash BLOB,\n    link_target   TEXT,\n    size          INTEGER NOT NULL DEFAULT 0\n  )", "CREATE TABLE IF NOT EXISTS vfs_dirents (\n    parent_inode INTEGER NOT NULL,\n    name         TEXT    NOT NULL,\n    child_inode  INTEGER NOT NULL,\n    PRIMARY KEY (parent_inode, name)\n  ) WITHOUT ROWID", "CREATE INDEX IF NOT EXISTS vfs_dirents_by_child ON vfs_dirents(child_inode)", "CREATE INDEX IF NOT EXISTS vfs_nodes_by_rev ON vfs_nodes(rev)", "CREATE INDEX IF NOT EXISTS vfs_nodes_by_manifest_hash\n    ON vfs_nodes(manifest_hash) WHERE manifest_hash IS NOT NULL", "CREATE TABLE IF NOT EXISTS vfs_blobs (\n    hash      BLOB    PRIMARY KEY,\n    size      INTEGER NOT NULL,\n    last_seen INTEGER NOT NULL\n  )", "CREATE TABLE IF NOT EXISTS vfs_blob_bytes (\n    hash  BLOB PRIMARY KEY REFERENCES vfs_blobs(hash) ON DELETE CASCADE,\n    bytes BLOB NOT NULL\n  )", "CREATE TABLE IF NOT EXISTS vfs_chunks (\n    inode INTEGER NOT NULL,\n    idx   INTEGER NOT NULL,\n    hash  BLOB    NOT NULL,\n    size  INTEGER NOT NULL,\n    PRIMARY KEY (inode, idx)\n  ) WITHOUT ROWID", "CREATE INDEX IF NOT EXISTS vfs_chunks_by_hash ON vfs_chunks(hash)"];
